(1, 1, 1, 30, 30, 0, 0.2, 1, 0, 0, 0, 0.5, 0.5, '{\"logo\":\"1_logo.png\",\"signature\":\"1_signature.png\",\"college_name\":\"<b>GOVERNMENT POLYTECHNIC, NASHIK<\\/b>\",\"section_name\":\"(An Academically Autonomous Institute of Government of Maharashtra )\",\"institute_address\":\"New Building Campus, Samangaon Road, Nashik Road, Nashik.\",\"ref_no\":\"GPN\\/PTII\\/Exam\\/2026\\/\",\"order_by\":\"<b>Office Order(Confidential)<\\/b>\",\"reference\":\"<b>Controller of Examination , Outword No. 78, Date: 11\\/03\\/2026<\\/b>\",\"department\":\"Department of\",\"college_address\":\"Government Polytechnic, Nashik\",\"subject_name\":\"Appointment as a Supervisor for Progressive Test II\",\"body_para_1\":\"Sir \\/ Madam,\",\"body_para_2\":\"With reference to the above cited subject, you are appointed as supervisor for progressive test II\",\"body_para_3\":\"<b>As show in table Below :<\\/b>\",\"show_table\":\"yes\",\"closing_text\":\"<div><b>INSTRUCTIONS :<\\/b><\\/div><div>1. All appointed supervisor must report to the examination control room <b>30 minutes before<\\/b> the examination and record their reporting time.<\\/div><div>2. Examination materials must be collected, counted and verified before proceeding to the allotted examination room.<\\/div><div>3. Supervisors must reach the examination room <b>20 minutes<\\/b> before the start of the examination.<\\/div><div>4. The examinee will not be allowed to appear for examination if reported more than <b>15 minutes<\\/b> late from the start of examination<\\/div><div>5. Hall tickets and identity cards must be verified; mobile phones and electronic gadgets are strictly prohibited.<\\/div><div>6. Instructions related to examination must be clearly communicated to the examinee.<\\/div><div>7. After the examination answer books must be collected in order, verified with the attendance sheet and submitted to the control room.<\\/div>\",\"official_designation\":\"Chief Officer Incharge\",\"off_name\":\"Principal&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;\",\"off_address\":\"Government Polytechnic, Nashik\"}', NULL, NULL);
